from itertools import combinations

class Solution:
    def maximumTastiness(self, price, k):
        best = 0
        for combo in combinations(sorted(price), k):
            diffs = [combo[i + 1] - combo[i] for i in range(len(combo) - 1)]
            m = min(diffs) if diffs else 0
            best = max(best, m)
        return best

