var maximumTastiness = function(price, k) {
    const sorted = price.slice().sort((a, b) => a - b);
    function feasible(d) {
        if (d === 0) return true;
        let count = 1;
        let last = sorted[0];
        for (let i = 1; i < sorted.length; i++) {
            if (sorted[i] - last >= d) {
                count++;
                last = sorted[i];
            }
        }
        return count >= k;
    }
    let lo = 0, hi = sorted[sorted.length - 1] - sorted[0];
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (feasible(mid)) lo = mid; else hi = mid - 1;
    }
    return lo;
};
